@pipermerriam totally agree. i don't want to pay for the overhead as a default. i should have addressed @MichaelRazum explicitly. it's somewhat trivial to implement on a per use case and providing a couple implementation examples might be more useful.  
as an explicit handler:
```python
def w3(web3=web3, logger=None, warning_msg=True):
    '''
        order providers by highest block number
        optionally provide warning for stale/dead HTTPProviders
    '''
    def get_block_int(p):
        return int(p.make_request('eth_blockNumber',[])['result'],16)

    good_providers, bad_providers = [], []
    for p in web3.providers:
        try:
            good_providers.append((p,get_block_int(p)))
        except Exception as e:
            bad_providers.append((p,e))

    if warning_msg and len(bad_providers) > 0:
        vals = (bad_providers, datetime.datetime.utcnow())
        msg = 'Not all of your HTPPProviders are able to connect: {},{}'.format(*vals)
        if logger is not None:
            logger.warning(msg)
        else:
            msg = 'Warning: ' + msg
            sys.stdout.write(msg)

    web3.manager.providers = [p[0] for p in sorted(good_providers,key=lambda x: x[1])]
    return web3
```  

after fiddling with it a bit more, i'd probably sort the providers as stoppable/pausable background task (as a user implementation):
```python
def threaded_provider_ranker(web3,t_stopper,snoozalito=5.0):
    def get_block_int(p):
        return int(p.make_request('eth_blockNumber',[])['result'],16)

    while not t_stopper.is_set():
        try:
            good_providers, bad_providers = [], []
            for p in web3.providers:
                try:
                    good_providers.append((p,get_block_int(p)))
                except Exception as e:
                    bad_providers.append((p,e))

            # <snip>

            if len(good_providers) > 0:
                web3.manager.providers = [p[0] for p in sorted(good_providers,key=lambda x: x[1])]
        except (KeyboardInterrupt, SystemExit):
            pass

        time.sleep(snoozalito)

# ....
t_stopper = threading.Event()
t = threading.Thread(target=threaded_provider_ranker, args=(web3,))
t.start()
...
