Short example of how I implemented it for anyone with the same problem:

    @staticmethod
    def _convert_relationships(db_model_class):
        converted_relationships = {}

        for prop_name, relationship in iteritems(db_model_class.__dict__):
            if not isinstance(relationship, Relationship):
                continue

            direction = relationship.direction
            model_name = relationship.target

            def get_graphql_model_class():
                module = import_module('example.models.' + model_module_name)
                return getattr(module, model_name, None)

            if direction == Direction.MANYTOONE or direction == Direction.ONETOONE:
                converted_relationships[prop_name] = Field(get_graphql_model_class)
            elif direction == Direction.ONETOMANY or direction == Direction.MANYTOMANY:
                converted_relationships[prop_name] = relay.ConnectionField(get_graphql_model_class)

        return converted_relationships

This uses a custom class Relationship that is added to the models, but should be clear enough to understand what is going on.

